#!/bin/bash
set -e
if echo dGVzdA== | base64 -D >/dev/null 2>&1; then B64FLAG="-D"; else B64FLAG="-d"; fi
mkdir -p components pages
echo 'Writing components/Nav.js...'
base64 $B64FLAG << 'B64_MOB_1' > components/Nav.js

B64_MOB_1
echo 'Writing pages/index.js...'
base64 $B64FLAG << 'B64_MOB_2' > pages/index.js

B64_MOB_2
echo 'Writing pages/rooms.js...'
base64 $B64FLAG << 'B64_MOB_3' > pages/rooms.js

B64_MOB_3
echo 'Writing pages/about.js...'
base64 $B64FLAG << 'B64_MOB_4' > pages/about.js

B64_MOB_4
echo 'Writing pages/contact.js...'
base64 $B64FLAG << 'B64_MOB_5' > pages/contact.js

B64_MOB_5
echo 'Writing pages/gallery.js...'
base64 $B64FLAG << 'B64_MOB_6' > pages/gallery.js

B64_MOB_6
echo 'Writing pages/booking.js...'
base64 $B64FLAG << 'B64_MOB_7' > pages/booking.js

B64_MOB_7
echo 'Mobile responsiveness fixes and guest limits applied.'
